  {
    "path": "telegram-group-scraper-tool/TelegramGroupScraper/Models/GroupMember.cs",
    "content": "namespace TelegramGroupScraper.Models;\n\n/// <summary>\n/// Represents a member of a Telegram group with basic profile information.\n/// </summary>\npublic class GroupMember\n{\n    /// <summary>\n    /// The unique user ID assigned by Telegram.\n    /// </summary>\n    public long UserId { get; set; }\n\n    /// <summary>\n    /// The user's first name (may be empty if not set).\n    /// </summary>\n    public string FirstName { get; set; } = string.Empty;\n\n    /// <summary>\n    /// The user's last name (may be empty if not set).\n    /// </summary>\n    public string LastName { get; set; } = string.Empty;\n\n    /// <summary>\n    /// The user's username (without @, may be null if not set).\n    /// </summary>\n    public string? Username { get; set; }\n\n    /// <summary>\n    /// The user's phone number (if available and visible).\n    /// </summary>\n    public string? PhoneNumber { get; set; }\n\n    /// <summary>\n    /// Whether the user is a bot.\n    /// </summary>\n    public bool IsBot { get; set; }\n\n    /// <summary>\n    /// Whether the user is a premium subscriber.\n    /// </summary>\n    public bool IsPremium { get; set; }\n\n    /// <summary>\n    /// The timestamp when this member data was scraped.\n    /// </summary>\n    public DateTime ScrapedAt { get; set; } = DateTime.UtcNow;\n\n    /// <summary>\n    /// Returns a CSV-formatted string of this member's data.\n    /// </summary>\n    public string ToCsv()\n    {\n        // Escape fields that may contain commas or quotes\n        string Escape(string? value) =>\n            value?.Contains(',') == true || value?.Contains('\"') == true\n                ? $\"\\\"{value.Replace(\"\\\"\", \"\\\"\\\"\")}\\\"\"\n                : value ?? string.Empty;\n\n        return $\"{UserId},{Escape(FirstName)},{Escape(LastName)},{Escape(Username)},{Escape(PhoneNumber)},{IsBot},{IsPremium},{ScrapedAt:O}\";\n    }\n\n    /// <summary>\n    /// Returns the CSV header line.\n    /// </summary>\n    public static string CsvHeader() =>\n        \"UserId,FirstName,LastName,Username,PhoneNumber,IsBot,IsPremium,ScrapedAt\";\n}"
  },
  {
    "path": "telegram-group-scraper-tool/TelegramGroupScraper/Services/TelegramClientService.cs",
    "content": "using Microsoft.Extensions.Logging;\nusing Microsoft.Extensions.Options;\nusing Telegram.Bot;\nusing Telegram.Bot.Types;\nusing Telegram.Bot.Types.Enums;\nusing TelegramGroupScraper.Configuration;\nusing TelegramGroupScraper.Models;\n\nnamespace TelegramGroupScraper.Services;\n\n/// <summary>\n/// Service responsible for interacting with Telegram API to scrape group members.\n/// Uses the TLSharp library for direct MTProto access (more efficient for member scraping).\n/// </summary>\npublic class TelegramClientService\n{\n    private readonly TelegramApiSettings _apiSettings;\n    private readonly ScraperSettings _scraperSettings;\n    private readonly ILogger<TelegramClientService> _logger;\n    private readonly TelegramBotClient? _botClient;\n\n    public TelegramClientService(\n        IOptions<TelegramApiSettings> apiOptions,\n        IOptions<ScraperSettings> scraperOptions,\n        ILogger<TelegramClientService> logger)\n    {\n        _apiSettings = apiOptions.Value;\n        _scraperSettings = scraperOptions.Value;\n        _logger = logger;\n\n        // Initialize bot client with the bot token (alternative approach)\n        // For full member scraping, TLSharp would be used, but here we demonstrate\n        // a bot-based approach for simplicity with real Telegram.Bot library\n        if (!string.IsNullOrEmpty(_apiSettings.BotToken))\n        {\n            _botClient = new TelegramBotClient(_apiSettings.BotToken);\n        }\n    }\n\n    /// <summary>\n    /// Scrapes members from a specified Telegram group.\n    /// Uses chat administrators and member list where available.\n    /// </summary>\n    /// <param name=\"groupUsername\">The group username (e.g., @mygroup) or chat ID.</param>\n    /// <param name=\"cancellationToken\">Cancellation token for long-running operations.</param>\n    /// <returns>A list of group members scraped from the group.</returns>\n    public async Task<List<GroupMember>> ScrapeGroupMembersAsync(\n        string groupUsername,\n        CancellationToken cancellationToken = default)\n    {\n        if (_botClient == null)\n        {\n            _logger.LogError(\"Bot client not initialized. Provide a BotToken in configuration.\");\n            return new List<GroupMember>();\n        }\n\n        var members = new List<GroupMember>();\n        long chatId;\n\n        try\n        {\n            // Resolve chat ID from username or direct ID\n            if (long.TryParse(groupUsername, out var parsedId))\n            {\n                chatId = parsedId;\n            }\n            else\n            {\n                // Remove @ if present\n                var cleanUsername = groupUsername.TrimStart('@');\n                var chat = await _botClient.GetChatAsync(cleanUsername, cancellationToken);\n                chatId = chat.Id;\n            }\n\n            _logger.LogInformation(\"Starting member scrape for chat {ChatId}\", chatId);\n\n            // Get chat administrators (always available for bots that are admins)\n            var admins = await _botClient.GetChatAdministratorsAsync(chatId, cancellationToken);\n            foreach (var admin in admins)\n            {\n                members.Add(MapUserToMember(admin.User));\n            }\n\n            _logger.LogInformation(\"Scraped {Count} administrators from chat {ChatId}\", admins.Length, chatId);\n\n            // For larger groups, attempt to get member count (limited info without being admin)\n            var chatFull = await _botClient.GetChatAsync(chatId, cancellationToken);\n            _logger.LogInformation(\"Chat {ChatId} has approximately {MemberCount} members\",\n                chatId, chatFull.MemberCount);\n\n            // Note: Full member list scraping requires MTProto API (TLSharp) or bot being admin\n            // with appropriate permissions. This is a demonstration of the structure.\n\n            await Task.Delay(_scraperSettings.RateLimitDelayMs, cancellationToken);\n        }\n        catch (Exception ex)\n        {\n            _logger.LogError(ex, \"Error scraping members from group {GroupUsername}\", groupUsername);\n            throw;\n        }\n\n        return members;\n    }\n\n    /// <summary>\n    /// Maps a Telegram User object to our GroupMember model.\n    /// </summary>\n    private static GroupMember MapUserToMember(User user)\n    {\n        return new GroupMember\n        {\n            UserId = user.Id,\n            FirstName = user.FirstName ?? string.Empty,\n            LastName = user.LastName ?? string.Empty,\n            Username = user.Username,\n            IsBot = user.IsBot,\n            IsPremium = user.IsPremium ?? false,\n            ScrapedAt = DateTime.UtcNow\n        };\n    }\n\n    /// <summary>\n    /// Validates that the API credentials are correctly configured.\n    /// </summary>\n    public bool ValidateConfiguration()\n    {\n        if (_apiSettings.ApiId <= 0)\n        {\n            _logger.LogError(\"Invalid ApiId: must be a positive integer.\");\n            return false;\n        }\n\n        if (string.IsNullOrEmpty(_apiSettings.ApiHash) || _apiSettings.ApiHash.Length < 10)\n        {\n            _logger.LogError(\"Invalid ApiHash: must be a valid hash string.\");\n            return false;\n        }\n\n        return true;\n    }\n}"
  },
  {
    "path": "telegram-group-scraper-tool/TelegramGroupScraper/Services/CsvExportService.cs",
    "content": "using System.Text;\nusing Microsoft.Extensions.Logging;\nusing Microsoft.Extensions.Options;\nusing TelegramGroupScraper.Configuration;\nusing TelegramGroupScraper.Models;\n\nnamespace TelegramGroupScraper.Services;\n\n/// <summary>\n/// Service for exporting scraped group member data to CSV files.\n/// </summary>\npublic class CsvExportService\n{\n    private readonly ScraperSettings _scraperSettings;\n    private readonly ILogger<CsvExportService> _logger;\n\n    public CsvExportService(\n        IOptions<ScraperSettings> scraperOptions,\n        ILogger<CsvExportService> logger)\n    {\n        _scraperSettings = scraperOptions.Value;\n        _logger = logger;\n    }\n\n    /// <summary>\n    /// Exports a list of group members to a CSV file.\n    /// </summary>\n    /// <param name=\"members\">The list of members to export.</param>\n    /// <param name=\"groupIdentifier\">The group name or ID for the filename.</param>\n    /// <param name=\"cancellationToken\">Cancellation token.</param>\n    /// <returns>The path to the exported CSV file.</returns>\n    public async Task<string> ExportToCsvAsync(\n        List<GroupMember> members,\n        string groupIdentifier,\n        CancellationToken cancellationToken = default)\n    {\n        // Ensure output directory exists\n        var outputDir = _scraperSettings.OutputDirectory;\n        if (!Directory.Exists(outputDir))\n        {\n            Directory.CreateDirectory(outputDir);\n            _logger.LogInformation(\"Created output directory: {OutputDir}\", outputDir);\n        }\n\n        // Create a safe filename from the group identifier\n        var safeName = SanitizeFilename(groupIdentifier);\n        var timestamp = DateTime.UtcNow.ToString(\"yyyyMMdd_HHmmss\");\n        var filePath = Path.Combine(outputDir, $\"members_{safeName}_{timestamp}.csv\");\n\n        _logger.LogInformation(\"Exporting {Count} members to {FilePath}\", members.Count, filePath);\n\n        var csvBuilder = new StringBuilder();\n        csvBuilder.AppendLine(GroupMember.CsvHeader());\n\n        foreach (var member in members)\n        {\n            cancellationToken.ThrowIfCancellationRequested();\n            csvBuilder.AppendLine(member.ToCsv());\n        }\n\n        await File.WriteAllTextAsync(filePath, csvBuilder.ToString(), Encoding.UTF8, cancellationToken);\n\n        _logger.LogInformation(\"Successfully exported {Count} members to {FilePath}\", members.Count, filePath);\n        return filePath;\n    }\n\n    /// <summary>\n    /// Removes characters from a string that are invalid in filenames.\n    /// </summary>\n    private static string SanitizeFilename(string filename)\n    {\n        var invalidChars = Path.GetInvalidFileNameChars();\n        var sanitized = new string(filename\n            .Where(ch => !invalidChars.Contains(ch))\n            .ToArray());\n\n        // Replace spaces with underscores and trim\n        sanitized = sanitized.Replace(' ', '_');\n\n        // If empty after sanitization, use a default\n        if (string.IsNullOrWhiteSpace(sanitized))\n        {\n            sanitized = \"unknown_group\";\n        }\n\n        return sanitized;\n    }\n}"
  },
  {
    "path": "telegram-group-scraper-tool/TelegramGroupScraper/Configuration/TelegramApiSettings.cs",
    "content": "namespace TelegramGroupScraper.Configuration;\n\n/// <summary>\n/// Configuration settings for Telegram API connection.\n/// </summary>\npublic class TelegramApiSettings\n{\n    /// <summary>\n    /// The API ID obtained from my.telegram.org.\n    /// </summary>\n    public int ApiId { get; set; }\n\n    /// <summary>\n    /// The API hash obtained from my.telegram.org.\n    /// </summary>\n    public string ApiHash { get; set; } = string.Empty;\n\n    /// <summary>\n    /// The phone number associated with the Telegram account (for user client).\n    /// </summary>\n    public string PhoneNumber { get; set; } = string.Empty;\n\n    /// <summary>\n    /// Bot token for bot-based API access (alternative to user client).\n    /// </summary>\n    public string? BotToken { get; set; }\n\n    /// <summary>\n    /// Path to save/load the session file for authentication persistence.\n    /// </summary>\n    public string SessionPath { get; set; } = \"./session.dat\";\n}"
  },
